for(let i=0;i<=6;i++){const y=ymin+(ymax-ymin)*i/6,yp=Y(y);svgAdd(svg,'line',{x1:m.l,y1:yp,x2:W-m.r,y2:yp,stroke:'#e5e7eb'});svgAdd(svg,'text',{x:m.l-9,y:yp+4,'text-anchor':'end','font-size':11,fill:'#64748b'},fmt(y,2))}
for(let i=0;i<=8;i++){const x=xmin+(xmax-xmin)*i/8,xp=X(x);svgAdd(svg,'line',{x1:xp,y1:m.t,x2:xp,y2:H-m.b,stroke:'#eef2f7'});svgAdd(svg,'text',{x:xp,y:H-m.b+23,'text-anchor':'middle','font-size':11,fill:'#64748b'},fmt(x,0))}
svgAdd(svg,'line',{x1:X(currentConfig.f0/1e3),y1:m.t,x2:X(currentConfig.f0/1e3),y2:H-m.b,stroke:'#94a3b8','stroke-dasharray':'4 5'});svgAdd(svg,'text',{x:X(currentConfig.f0/1e3)+5,y:m.t+13,'font-size':10,fill:'#64748b'},'f0');
