const colors=['#06b6d4','#2563eb','#0f3f78'];curves.forEach((c,i)=>{let seg=[];const flush=()=>{if(seg.length>1)svgAdd(svg,'path',{d:seg.map((p,j)=>(j?'L':'M')+X(p.fs/1e3)+','+Y(p.gain)).join(' '),fill:'none',stroke:colors[i],'stroke-width':i===1?3.2:2.5,'stroke-linejoin':'round'});seg=[]};c.pts.forEach(p=>{if(Number.isFinite(p.gain))seg.push(p);else flush()});flush()});
// input target lines
svgAdd(svg,'line',{x1:m.l,y1:Y(gHi),x2:W-m.r,y2:Y(gHi),stroke:'#dc2626','stroke-width':2,'stroke-dasharray':'8 6'});svgAdd(svg,'text',{x:W-m.r-5,y:Y(gHi)-7,'text-anchor':'end','font-size':11,'font-weight':850,fill:'#b91c1c'},`Vin,min target ${fmt(gHi,3)}`);svgAdd(svg,'line',{x1:m.l,y1:Y(gLo),x2:W-m.r,y2:Y(gLo),stroke:'#f97316','stroke-width':2,'stroke-dasharray':'8 6'});svgAdd(svg,'text',{x:W-m.r-5,y:Y(gLo)+16,'text-anchor':'end','font-size':11,'font-weight':850,fill:'#c2410c'},`Vin,max target ${fmt(gLo,3)}`);
// 9 exact operating points
const loadColors=colors;for(const c of selected.corners||[]){if(!c.valid||!Number.isFinite(c.fs))continue;const li=currentConfig.loads.findIndex(x=>Math.abs(x-c.load)<1e-7),g=targetGainForVin(c.vin),cx=X(c.fs/1e3),cy=Y(g);if(cx<m.l||cx>W-m.r||cy<m.t||cy>H-m.b)continue;svgAdd(svg,'circle',{cx,cy,r:5.2,fill:loadColors[Math.max(0,li)]||'#111827',stroke:'#fff','stroke-width':2});svgAdd(svg,'circle',{cx,cy,r:6.5,fill:'none',stroke:'#111827','stroke-width':.7,opacity:.45})}
