function renderStatePlot(w){const svg=$('statePlot');svg.innerHTML='';const pts=w.statePoints||w.points||[],W=900,H=520,m={l:76,r:24,t:32,b:58};if(pts.length<2){drawPlaceholder('statePlot',ui.stateCalcFail);return}const xs=pts.map(p=>p.vcr),ys=pts.map(p=>p.ir),xmin=Math.min(...xs),xmax=Math.max(...xs),yabs=Math.max(...ys.map(Math.abs),1),xpad=.09*(xmax-xmin||1),X=x=>m.l+(x-(xmin-xpad))/(xmax-xmin+2*xpad)*(W-m.l-m.r),Y=y=>H-m.b-(y+yabs*1.12)/(2*yabs*1.12)*(H-m.t-m.b);svgAdd(svg,'rect',{x:0,y:0,width:W,height:H,fill:'#fff'});for(let i=0;i<=6;i++){const xv=xmin-xpad+(xmax-xmin+2*xpad)*i/6,xp=X(xv);svgAdd(svg,'line',{x1:xp,y1:m.t,x2:xp,y2:H-m.b,stroke:'#eef2f7'});svgAdd(svg,'text',{x:xp,y:H-m.b+22,'text-anchor':'middle','font-size':11,fill:'#64748b'},fmt(xv,0))}for(let i=0;i<=6;i++){const yv=-yabs*1.12+2*yabs*1.12*i/6,yp=Y(yv);svgAdd(svg,'line',{x1:m.l,y1:yp,x2:W-m.r,y2:yp,stroke:'#eef2f7'});svgAdd(svg,'text',{x:m.l-8,y:yp+4,'text-anchor':'end','font-size':11,fill:'#64748b'},fmt(yv,1))}svgAdd(svg,'line',{x1:m.l,y1:Y(0),x2:W-m.r,y2:Y(0),stroke:'#94a3b8'});const modeColor={1:'#2563eb',0:'#f59e0b','-1':'#7c3aed'};let seg=[pts[0]],mode=pts[1]?.mode??pts[0].mode;const flush=()=>{if(seg.length>1)svgAdd(svg,'path',{d:seg.map((p,i)=>(i?'L':'M')+X(p.vcr)+','+Y(p.ir)).join(' '),fill:'none',stroke:modeColor[mode], 'stroke-width':3.2,'stroke-linecap':'round','stroke-linejoin':'round'});seg=[]};for(let i=1;i<pts.length;i++){const p=pts[i];if(p.mode!==mode){flush();seg=[pts[i-1],p];mode=p.mode}else seg.push(p)}flush();const edges=pts.map((p,i)=>p.edge?i:-1).filter(i=>i>=0);edges.forEach((idx,j)=>{const p=pts[idx];svgAdd(svg,'circle',{cx:X(p.vcr),cy:Y(p.ir),r:5,fill:'#111827',stroke:'#fff','stroke-width':1.5});svgAdd(svg,'text',{x:X(p.vcr)+8,y:Y(p.ir)-8,'font-size':12,'font-weight':900,fill:'#111827'},j===0?'A':'C')});for(let i=14;i<pts.length;i+=Math.max(20,Math.floor(pts.length/18))){const a=pts[i-1],b=pts[i],dx=X(b.vcr)-X(a.vcr),dy=Y(b.ir)-Y(a.ir),l=Math.hypot(dx,dy)||1,ux=dx/l,uy=dy/l,x=X(b.vcr),y=Y(b.ir);svgAdd(svg,'path',{d:`M${x},${y} l${-7*ux+4*uy},${-7*uy-4*ux} M${x},${y} l${-7*ux-4*uy},${-7*uy+4*ux}`,stroke:modeColor[b.mode], 'stroke-width':1.5,fill:'none'})}svgAdd(svg,'line',{x1:m.l,y1:H-m.b,x2:W-m.r,y2:H-m.b,stroke:'#111827'});svgAdd(svg,'line',{x1:m.l,y1:m.t,x2:m.l,y2:H-m.b,stroke:'#111827'});svgAdd(svg,'text',{x:W/2,y:H-14,'text-anchor':'middle','font-size':14,'font-weight':800,fill:'#334155'},'vCr [V]');svgAdd(svg,'text',{x:22,y:H/2,'text-anchor':'middle','font-size':14,'font-weight':800,fill:'#334155',transform:`rotate(-90 22 ${H/2})`},'iLr [A]');svgAdd(svg,'text',{x:W/2,y:22,'text-anchor':'middle','font-size':15,'font-weight':850,fill:'#111827'},`${zh?'ODE 状态平面':'ODE state-plane'} · Vo=${fmt(w.Vo,3)} V · fs=${fmt(w.fs/1e3,2)} kHz`)}
function renderStateSummary(w){const c=selected.corners[selectedCornerIndex],pts=w.statePoints||w.points||[],free=pts.filter(p=>p.mode===0).length/Math.max(1,pts.length),trans=[];for(let i=1;i<pts.length;i++)if(pts[i].mode!==pts[i-1].mode)trans.push({from:pts[i-1].mode,to:pts[i].mode,t:pts[i].t});const modeText=free>.01?ui.discontinuous:ui.continuous,worst=free>.15?ui.longFree:free>.01?ui.hasFree:ui.clampStates;$('stateSummary').innerHTML=`<h3>${cornerName(c)}</h3><div class="mode-card"><b>${modeText}</b><br>${worst}</div><div class="kv"><div><b>${ui.switchingFrequency}</b><span>${fmt(w.fs/1e3,2)} kHz</span></div><div><b>fs / f0</b><span>${fmt(w.fs/currentConfig.f0,3)}</span></div><div><b>Ir,pk</b><span>${fmt(c.ipk,3)} A</span></div><div><b>Ir,rms</b><span>${fmt(c.irms,3)} A</span></div><div><b>VCr,pk</b><span>${fmt(c.vcrpk,1)} V</span></div><div><b>${ui.commutationCurrent}</b><span>${fmt(c.comm,3)} A</span></div><div><b>${ui.freeInterval}</b><span>${fmt(c.freePct,1)}%</span></div><div><b>${ui.stateTransitions}</b><span>${trans.length}</span></div></div><div class="mode-card" style="margin-top:10px"><b>${ui.readPlot}</b><br>${ui.readPlotText}</div>`}
function renderWavePlot(w){const svg=$('wavePlot');svg.innerHTML='';const W=1220,H=520,left=68,right=18,top=24,bottom=42,gap=12,rows=4,rh=(H-top-bottom-gap*(rows-1))/rows,pts=w.points;if(!pts?.length){drawPlaceholder('wavePlot',ui.waveCalcFail);return}const tmax=pts[pts.length-1].t*1e6,X=t=>left+t*1e6/tmax*(W-left-right),series=[['vCr [V]','vcr'],['iLr / iLm [A]','curr'],[zh?'整流电流 [A]':'Rectified current [A]','io'],[zh?'桥臂电压 [V]':'Bridge voltage [V]','vs']];svgAdd(svg,'rect',{x:0,y:0,width:W,height:H,fill:'#fff'});series.forEach((s,ri)=>{const y0=top+ri*(rh+gap),keys=s[1]==='curr'?['ir','im']:[s[1]],values=pts.flatMap(p=>keys.map(k=>p[k])).filter(Number.isFinite),mn=Math.min(...values),mx=Math.max(...values),pad=.12*(mx-mn||1),lo=mn-pad,hi=mx+pad,Y=v=>y0+rh-(v-lo)/(hi-lo||1)*rh;for(let j=0;j<=4;j++){const x=left+(W-left-right)*j/4;svgAdd(svg,'line',{x1:x,y1:y0,x2:x,y2:y0+rh,stroke:'#eef2f7'})}for(let j=0;j<=2;j++){const v=lo+(hi-lo)*j/2,y=Y(v);svgAdd(svg,'line',{x1:left,y1:y,x2:W-right,y2:y,stroke:'#eef2f7'});svgAdd(svg,'text',{x:left-7,y:y+4,'text-anchor':'end','font-size':10,fill:'#64748b'},Math.abs(v)>20?fmt(v,0):fmt(v,2))}const cols=['#2563eb','#ef4444'];keys.forEach((k,ki)=>svgAdd(svg,'path',{d:pts.map((p,i)=>(i?'L':'M')+X(p.t)+','+Y(p[k])).join(' '),fill:'none',stroke:cols[ki],'stroke-width':2.1,'stroke-linejoin':'round'}));pts.filter(p=>p.edge).forEach(p=>svgAdd(svg,'line',{x1:X(p.t),y1:y0,x2:X(p.t),y2:y0+rh,stroke:'#111827','stroke-width':1,'stroke-dasharray':'3 4',opacity:.65}));svgAdd(svg,'text',{x:8,y:y0+15,'font-size':11,'font-weight':800,fill:'#334155'},s[0]);if(s[1]==='curr'){svgAdd(svg,'text',{x:W-right-5,y:y0+14,'text-anchor':'end','font-size':10,'font-weight':800,fill:'#2563eb'},'iLr');svgAdd(svg,'text',{x:W-right-5,y:y0+28,'text-anchor':'end','font-size':10,'font-weight':800,fill:'#ef4444'},'iLm')}});for(let j=0;j<=4;j++){const x=left+(W-left-right)*j/4;svgAdd(svg,'text',{x,y:H-15,'text-anchor':'middle','font-size':10,fill:'#64748b'},fmt(tmax*j/4,2))}svgAdd(svg,'text',{x:W/2,y:H-2,'text-anchor':'middle','font-size':11,fill:'#334155'},`${zh?'时间':'time'} [µs] · 3 ${zh?'周期':'periods'} · Vo=${fmt(w.Vo,3)} V · residual=${fmt(w.residual,4)}`)}
drawPlaceholder('gainPlot',ui.selectEnvelope);drawPlaceholder('statePlot',ui.selectState);drawPlaceholder('wavePlot',ui.selectWave);
